+/**
+ * Normalize JSONL / SSE payloads: stored logs often use `agent_message` (full turn) because
+ * `agent_message_chunk` is stripped before S3 append; some lines omit top-level `type`.
+ */
+function coerceACPNotification(parsed: unknown): ACPNotification | null {
+    if (typeof parsed !== 'object' || parsed === null) {
+        return null
+    }
+    const obj = parsed as Record<string, unknown>
+    if (obj.type === 'notification' && 'notification' in obj) {
+        return obj as unknown as ACPNotification
+    }
+    const notifRaw = obj.notification
+    if (typeof notifRaw !== 'object' || notifRaw === null) {
+        return null
+    }
+    const method = (notifRaw as { method?: string }).method
+    if (
+        method === 'session/update' ||
+        method === '_posthog/console' ||
+        (typeof method === 'string' && method.startsWith('_posthog/'))
+    ) {
+        return {
+            type: 'notification',
+            timestamp: typeof obj.timestamp === 'string' ? obj.timestamp : '',
+            notification: notifRaw as ACPNotification['notification'],
+        }
+    }
+    return null
+}
